    def run(self):
        # Fetch and install packages needed at install time before the main install
        config = get_dependencies()
        install_time_packages = config.get("install_time_packages", [])

        if install_time_packages:
            print("=" * 60)
            print("Installing install-time dependencies...")
            print("=" * 60)
            pip_install(install_time_packages)

        # Run the standard install
