        # Post-install: install any post-install packages
        post_install_packages = config.get("post_install_packages", [])
        if post_install_packages:
            print("=" * 60)
            print("Installing post-install dependencies...")
            print("=" * 60)
            pip_install(post_install_packages)

        print("=" * 60)
        print("Installation complete!")
        print("=" * 60)


